.include "runtime.inc"

.segment "TESTS"

; Rewrite the tilemap with tile indices that both EXIST and are NON-BLANK in a deep mode.
;
; Two constraints, and missing the second is the subtler mistake. A tile must lie inside
; the font: 8bpp is 32 words/tile against a 1024-word font, so $00-$1F exist. It must also
; cover PRINTABLE glyphs, and how many glyphs a tile spans depends on the depth: a 4bpp
; tile covers glyphs 2T and 2T+1, an 8bpp tile covers 4T..4T+3. So $10-$1F is glyphs 32-63
; at 4bpp and 64-127 at 8bpp — printable at both. Anything below $10 lands on ASCII 0-31,
; the control characters, which are blank in this font.
;
; This cost two rounds. $00-$0F rendered an EMPTY screen in mode 2 while mode 4 looked
; fine, which reads as a broken mode; $08-$0F fixed 8bpp and left 4bpp still blank, which
; reads as a broken depth. Neither was true. An empty scene hashes stably and the
; reference emulators agree with it, so only looking at the picture finds this.
;
; WIDTH-NEUTRAL: P is saved and restored, so the A/X/Y widths on exit are
; exactly what they were on entry. Deliberate rather than merely tidy: the
; caller is generated assembly whose .a8/.a16 directives come from its OWN
; sep/rep lines, and a JSR is not one of those — so a helper that changed
; the width would leave the assembler believing one thing while the CPU did
; another, and the next immediate operand would be assembled at the wrong
; size. That failure already cost this project a debugging session; see the
; .a8/.a16 emission in `asm` below.
.proc scene_low_tiles
    php
    .a16
    .i16
    sep #$20
    .a8
    lda #$80
    sta VMAIN
    rep #$30
    .a16
    .i16
    ldx #MAP_BASE
    stx VMADDL
    ldx #$0000
@cell:
    txa
    lsr a
    lsr a
    lsr a
    lsr a
    lsr a             ; row
    sta f:V_TMP2
    txa
    clc
    adc f:V_TMP2      ; tile varies with row AND column: a column-constant map cannot
                      ; show a vertical shift, which is how the first OPT scenes came
                      ; out identical to their own control.
    and #$000F
    ora #$0010        ; tile $10-$1F: inside the font AND printable at 4bpp and 8bpp
    sta f:V_TMP
    lda f:V_TMP2
    and #$0007
    .repeat 10
    asl a
    .endrepeat
    ora f:V_TMP       ; palette in bits 10-12
    sta VMDATAL
    inx
    cpx #(SCREEN_COLS * 32)
    bne @cell
    plp               ; restore the caller's register widths
    rts
.endproc

; Fill BG3's tilemap with offset-per-tile entries (see scenes.rs::opt_map_helper).
; Reads V_OPT_H_EVEN / V_OPT_H_ODD (row 0) and V_OPT_V_EVEN / V_OPT_V_ODD (row 1).
.proc scene_opt_map
    php
    .a16
    .i16
    sep #$20
    .a8
    lda #$80
    sta VMAIN
    rep #$30
    .a16
    .i16
    ldx #OPT_MAP_BASE
    stx VMADDL
    ldx #$0000                ; cell index across the whole 32x32 map
@cell:
    txa
    cmp #SCREEN_COLS          ; row 0?
    bcs :+
    bcc @row0
  :
    cmp #(SCREEN_COLS * 2)    ; row 1?
    bcc @row1
    lda #$0000                ; every other row is empty
    bra @put
@row0:
    txa
    and #$0001
    bne :+
    lda f:V_OPT_H_EVEN
    bra @put
  :
    lda f:V_OPT_H_ODD
    bra @put
@row1:
    txa
    and #$0001
    bne :+
    lda f:V_OPT_V_EVEN
    bra @put
  :
    lda f:V_OPT_V_ODD
@put:
    sta VMDATAL
    inx
    cpx #(SCREEN_COLS * 32)
    bne @cell
    plp                       ; restore the caller's register widths
    rts
.endproc

; Mode 7 VRAM: tilemap in the low bytes, character data in the high bytes, one pass.
.proc scene_mode7_vram
    php
    .a16
    .i16
    sep #$20
    .a8
    lda #$80
    sta VMAIN
    rep #$30
    .a16
    .i16
    ldx #$0000
    stx VMADDL
@cell:
    ; low byte = tilemap entry: a 16x16 grid of distinct tiles across the 128x128 map.
    txa
    and #$007F                ; map column 0-127
    lsr a
    lsr a
    lsr a                     ; column / 8 -> 0-15
    sta f:V_TMP
    txa
    lsr a
    lsr a
    lsr a
    lsr a
    lsr a
    lsr a
    lsr a                     ; map row 0-127
    lsr a
    lsr a
    lsr a                     ; row / 8 -> 0-15
    asl a
    asl a
    asl a
    asl a                     ; row block * 16
    ora f:V_TMP               ; tile 0-255, distinct per 8x8 block of the map
    and #$00FF
    sta f:V_TMP
    ; high byte = character data: the word index PLUS ONE, so each tile is a colour
    ; gradient and character 0's pixel (0,0) is non-zero. That last part matters: at a
    ; large zoom every out-of-range pixel samples the same sub-pixel, so if char 0 pixel
    ; (0,0) were colour 0 the char-0 screen-over mode would render transparent and be
    ; indistinguishable from the transparent mode -- which it was, on all three emulators.
    txa
    inc a
    and #$00FF
    xba                       ; into the high byte
    ora f:V_TMP
    sta VMDATAL               ; one 16-bit store writes both halves
    inx
    cpx #$4000                ; 16384 words = the whole Mode 7 area
    bne @cell
    plp
    rts
.endproc
; Fill the tilemap screen after the canvas (see scenes.rs::second_screen_helper).
.proc scene_second_screen
    php
    .a16
    .i16
    sep #$20
    .a8
    lda #$80
    sta VMAIN
    rep #$30
    .a16
