    ldx #(MAP_BASE + $400)   ; the second 32x32 screen, one screen on from the canvas
    stx VMADDL
    ldx #$0000
@cell:
    txa
    and #$000F
    ora #$0020        ; tiles $20-$2F: printable, and outside the canvas's $10-$1F
    ora #$1400        ; palette 5, which the canvas's row-derived palettes do not favour
    sta VMDATAL
    inx
    cpx #(SCREEN_COLS * 32)
    bne @cell
    plp
    rts
.endproc

; Park all 128 sprites off-screen and point OBJ character data at the font.
.proc scene_oam_reset
    php
    .a16
    .i16
    sep #$20
    .a8
    lda #$20
    sta $2101         ; OBJSEL: size pair 1 (8x8 / 16x16), name base word $0000
    rep #$10
    .i16
    ldx #$0000
    stx $2102         ; OAMADD = 0

    ; A stays 8-bit and X stays 16-bit for both loops. OAM is written a byte at a time and
    ; the counters only need the index width, so flipping the accumulator inside the loop
    ; would be 160 pointless `sep`/`rep` pairs and one more place to get a width wrong.
    ldx #$0000
@low:
    lda #$00
    sta $2104         ; X low
    lda #224
    sta $2104         ; Y = 224: off the bottom, so no range or sliver slot is used
    lda #$00
    sta $2104         ; tile
    sta $2104         ; attributes
    inx
    cpx #128
    bne @low
    ldx #$0000
    lda #$00
@high:
    sta $2104         ; high table: X bit 8 clear, size bit clear
    inx
    cpx #32
    bne @high
    plp
    rts
.endproc

